#!/usr/bin/env python3
"""
System Preferences, Dock Layout, and Conflict Detection

Generate JSON execution plan describing system preferences, Dock layout, and destination conflicts.
"""

import argparse
import json
import os
import sys
from dataclasses import dataclass, field
from enum import Enum
from pathlib import Path
from typing import Any, Optional

import yaml


class SchemaType(Enum):
    MODULE = "module"
    PREFERENCES = "preferences"
    DOCK = "dock"


# OS version ordering (oldest to newest)
OS_VERSIONS = [
    "yosemite",
    "el_capitan",
    "sierra",
    "high_sierra",
    "mojave",
    "catalina",
    "big_sur",
    "monterey",
    "ventura",
    "sonoma",
]

VALID_VALUE_TYPES = {"bool", "int", "string", "float"}


@dataclass
class ValidationError:
    message: str
    file: Optional[str] = None
    line: Optional[int] = None


@dataclass
class PreferenceEntry:
    name: str
    domain: str
    key: str
    value: Any
    value_type: str
    apply_command: str
    check_command: Optional[str] = None
    expected_state: Optional[str] = None
    min_version: Optional[str] = None
    max_version: Optional[str] = None
    enabled: bool = True

    def to_plan_action(self) -> dict:
        action = {
            "type": "set_preference",
            "name": self.name,
            "domain": self.domain,
            "key": self.key,
            "value": self.value,
            "value_type": self.value_type,
            "apply_command": self.apply_command,
        }
        if self.check_command is not None:
            action["check_command"] = self.check_command
        if self.expected_state is not None:
            action["expected_state"] = self.expected_state
        return action

    def matches_version(self, os_version: Optional[str]) -> bool:
        """Check if this preference should be included for the given OS version."""
        if not self.enabled:
            return False
        if os_version is None:
            return True

        # Validate versions
        if self.min_version is not None and self.min_version not in OS_VERSIONS:
            return False
        if self.max_version is not None and self.max_version not in OS_VERSIONS:
            return False

        min_idx = 0
        if self.min_version is not None:
            min_idx = OS_VERSIONS.index(self.min_version)

        max_idx = len(OS_VERSIONS) - 1
        if self.max_version is not None:
            max_idx = OS_VERSIONS.index(self.max_version)

        if os_version not in OS_VERSIONS:
            return False

        target_idx = OS_VERSIONS.index(os_version)

        return min_idx <= target_idx <= max_idx


@dataclass
class DockEntry:
    os: str
    items: list[str]

    def to_plan_action(self) -> dict:
        return {
            "type": "configure_dock",
            "items": self.items,
        }


@dataclass
class ModuleConfig:
    name: str
    directory: Path
    schema_type: SchemaType
    preferences: list[PreferenceEntry] = field(default_factory=list)
    dock: Optional[DockEntry] = None
    packages: list[str] = field(default_factory=list)
    package_manager: Optional[str] = None
    file_actions: list[dict] = field(default_factory=list)
    applications: list[str] = field(default_factory=list)


@dataclass
class PlanModule:
    name: str
    actions: list[dict]


@dataclass
class Conflict:
    destination: str
    sources: list[dict]


def validate_preference_entry(data: dict, index: int) -> list[ValidationError]:
    errors = []
    prefix = f"preferences[{index}]"

    # Required fields
    for field in ["name", "domain", "key", "value", "value_type", "apply_command"]:
        if field not in data:
            errors.append(ValidationError(message=f"{prefix}.{field} is required"))

    # Validate value_type
    if "value_type" in data:
        vt = data["value_type"]
        if vt not in VALID_VALUE_TYPES:
            errors.append(
                ValidationError(
                    message=f"{prefix}.value_type: must be 'bool', 'int', 'string', or 'float', got '{vt}'"
                )
            )

    # Validate min_version
    if "min_version" in data:
        mv = data["min_version"]
        if mv not in OS_VERSIONS:
            errors.append(
                ValidationError(message=f"{prefix}.min_version: unknown version '{mv}'")
            )

    # Validate max_version
    if "max_version" in data:
        mv = data["max_version"]
        if mv not in OS_VERSIONS:
            errors.append(
                ValidationError(message=f"{prefix}.max_version: unknown version '{mv}'")
            )

    # Validate version range
    if "min_version" in data and "max_version" in data:
        min_v = data["min_version"]
        max_v = data["max_version"]
        if min_v in OS_VERSIONS and max_v in OS_VERSIONS:
            if OS_VERSIONS.index(min_v) > OS_VERSIONS.index(max_v):
                errors.append(
                    ValidationError(
                        message=f"{prefix}: min_version '{min_v}' is later than max_version '{max_v}'"
                    )
                )

    return errors


def validate_dock_entry(data: dict) -> list[ValidationError]:
    errors = []

    # os field
    if "os" not in data or data["os"] != "macos":
        errors.append(ValidationError(message="dock: 'os' is required and must be 'macos'"))

    # items field
    if "items" not in data:
        errors.append(ValidationError(message="dock: 'items' is required"))
    elif not isinstance(data["items"], list) or len(data["items"]) == 0:
        errors.append(ValidationError(message="dock: 'items' must be a non-empty list"))
    elif not all(isinstance(item, str) for item in data["items"]):
        errors.append(ValidationError(message="dock: 'items' must be a list of strings"))

    return errors


def parse_yaml_file(file_path: Path) -> tuple[Optional[dict], list[ValidationError]]:
    """Parse a YAML file and return its contents or errors."""
    errors = []
    try:
        with open(file_path, "r") as f:
            data = yaml.safe_load(f)
            if data is None:
                errors.append(ValidationError(message=f"{file_path}: empty file"))
                return None, errors
            return data, errors
    except yaml.YAMLError as e:
        errors.append(ValidationError(message=f"{file_path}: YAML parse error: {e}"))
        return None, errors
    except Exception as e:
        errors.append(ValidationError(message=f"{file_path}: error reading file: {e}"))
        return None, errors


def discover_configs(root_dir: Path) -> tuple[list[ModuleConfig], list[ValidationError]]:
    """Discover all config files in the directory tree."""
    errors = []
    modules = []
    dock_count = 0
    dock_files = []

    # Find all YAML files
    yaml_files = list(root_dir.rglob("*.yaml")) + list(root_dir.rglob("*.yml"))

    # Group by directory
    dir_configs: dict[Path, dict[str, Any]] = {}
    for yaml_file in yaml_files:
        dir_path = yaml_file.parent
        if dir_path not in dir_configs:
            dir_configs[dir_path] = {}
        dir_configs[dir_path][yaml_file.name] = yaml_file

    # Process each directory
    for dir_path, files in dir_configs.items():
        module_name = dir_path.name
        module_dir = dir_path
        module_schema = None
        preferences_data = None
        dock_data = None

        # Check for module.yaml
        if "module.yaml" in files or "module.yml" in files:
            module_file = files.get("module.yaml") or files.get("module.yml")
            data, parse_errors = parse_yaml_file(module_file)
            errors.extend(parse_errors)
            if data:
                if data.get("schema") == "module":
                    module_schema = SchemaType.MODULE
                    # Parse module-specific fields
                    # For now, we'll handle packages separately

        # Check for preferences.yaml
        if "preferences.yaml" in files or "preferences.yml" in files:
            prefs_file = files.get("preferences.yaml") or files.get("preferences.yml")
            data, parse_errors = parse_yaml_file(prefs_file)
            errors.extend(parse_errors)
            if data and data.get("schema") == "preferences":
                preferences_data = data

        # Check for dock.yaml
        if "dock.yaml" in files or "dock.yml" in files:
            dock_file = files.get("dock.yaml") or files.get("dock.yml")
            data, parse_errors = parse_yaml_file(dock_file)
            errors.extend(parse_errors)
            if data and data.get("schema") == "dock":
                dock_data = data
                dock_count += 1
                dock_files.append(str(dock_file))

        # Create module config
        if module_schema or preferences_data or dock_data:
            module = ModuleConfig(
                name=module_name,
                directory=module_dir,
                schema_type=module_schema if module_schema else SchemaType.PREFERENCES if preferences_data else SchemaType.DOCK
            )

            # Parse preferences if present
            if preferences_data:
                prefs_list = preferences_data.get("preferences", [])
                for i, pref in enumerate(prefs_list):
                    pref_errors = validate_preference_entry(pref, i)
                    errors.extend(pref_errors)

                    if not pref_errors:
                        entry = PreferenceEntry(
                            name=pref.get("name", ""),
                            domain=pref.get("domain", ""),
                            key=pref.get("key", ""),
                            value=pref.get("value"),
                            value_type=pref.get("value_type", ""),
                            apply_command=pref.get("apply_command", ""),
                            check_command=pref.get("check_command"),
                            expected_state=pref.get("expected_state"),
                            min_version=pref.get("min_version"),
                            max_version=pref.get("max_version"),
                            enabled=pref.get("enabled", True),
                        )
                        module.preferences.append(entry)

            # Parse dock if present
            if dock_data:
                dock_errors = validate_dock_entry(dock_data)
                errors.extend(dock_errors)

                if not dock_errors:
                    module.dock = DockEntry(
                        os=dock_data.get("os", ""),
                        items=dock_data.get("items", []),
                    )

            modules.append(module)

    # Check for multiple dock configs
    if dock_count > 1:
        errors.append(
            ValidationError(
                message="multiple 'dock' schemas found — only one is allowed",
                file=dock_files[0] if dock_files else None
            )
        )

    return modules, errors


def generate_plan(
    modules: list[ModuleConfig],
    os_filter: Optional[str] = None,
    os_version: Optional[str] = None,
    module_filter: Optional[list[str]] = None,
) -> tuple[list[PlanModule], list[Conflict]]:
    """Generate the execution plan with filtering and conflict detection."""

    # Apply filters
    filtered_modules = []
    for module in modules:
        # Module filter
        if module_filter and module.name not in module_filter:
            continue

        # OS filter for dock (only if os != macos)
        if module.dock and os_filter != "macos":
            module.dock = None

        filtered_modules.append(module)

    # Generate actions for each module
    plan_modules = []
    all_file_actions = []  # For conflict detection

    for module in filtered_modules:
        actions = []

        # Parse module.yaml for packages and applications
        module_file = module.directory / "module.yaml"
        if not module_file.exists():
            module_file = module.directory / "module.yml"

        if module_file.exists():
            data, _ = parse_yaml_file(module_file)
            if data and data.get("schema") == "module":
                # Parse packages
                if "os" in data and isinstance(data["os"], dict):
                    os_info = data["os"]
                    if os_info.get("name") == os_filter or os_filter is None:
                        if "package_manager" in os_info:
                            module.package_manager = os_info["package_manager"]
                        if "packages" in os_info:
                            module.packages = os_info["packages"]

        # Add package actions (sorted alphabetically)
        for pkg in sorted(module.packages):
            action = {
                "type": "install_package",
                "manager": module.package_manager or "unknown",
                "package": pkg,
            }
            actions.append(action)

        # Add application actions (sorted alphabetically)
        for app in sorted(module.applications):
            action = {
                "type": "install_application",
                "application": app,
            }
            actions.append(action)

        # Add file actions in config order
        for fa in module.file_actions:
            actions.append(fa)

        # Add preference actions (in order, filtered by version)
        for pref in module.preferences:
            if pref.matches_version(os_version):
                actions.append(pref.to_plan_action())

        # Add dock action (last, if exists)
        if module.dock:
            actions.append(module.dock.to_plan_action())

        plan_modules.append(PlanModule(name=module.name, actions=actions))

        # Collect file actions for conflict detection
        for action in actions:
            if action["type"] in ("link", "copy"):
                dest = action.get("destination", "")
                if dest:
                    all_file_actions.append({
                        "module": module.name,
                        "type": action["type"],
                        "source": action.get("source", ""),
                        "destination": dest,
                    })

    # Detect conflicts
    conflicts = detect_conflicts(all_file_actions)

    return plan_modules, conflicts


def detect_conflicts(file_actions: list[dict]) -> list[Conflict]:
    """Detect conflicts where multiple actions target the same destination."""
    dest_map: dict[str, list[dict]] = {}

    for action in file_actions:
        dest = action["destination"]
        if dest not in dest_map:
            dest_map[dest] = []
        dest_map[dest].append(action)

    conflicts = []
    for dest, sources in sorted(dest_map.items()):
        if len(sources) > 1:
            # Sort sources by module, then source, then type
            sorted_sources = sorted(sources, key=lambda s: (s["module"], s["source"], s["type"]))
            conflict_sources = [
                {"module": s["module"], "type": s["type"], "source": s["source"]}
                for s in sorted_sources
            ]
            conflicts.append(Conflict(destination=dest, sources=conflict_sources))

    return conflicts


def main():
    parser = argparse.ArgumentParser(
        description="Generate JSON execution plan for system preferences and Dock layout."
    )
    parser.add_argument(
        "command",
        choices=["plan"],
        help="Command to execute (currently only 'plan' is supported)"
    )
    parser.add_argument(
        "directory",
        type=Path,
        help="Root directory to search for config files"
    )
    parser.add_argument(
        "--os",
        choices=["macos", "linux"],
        help="Filter by operating system"
    )
    parser.add_argument(
        "--os-version",
        choices=OS_VERSIONS,
        help="Filter by OS version (affects preferences only)"
    )
    parser.add_argument(
        "--module",
        action="append",
        dest="modules",
        help="Filter by module name (can be specified multiple times)"
    )

    args = parser.parse_args()

    root_dir = args.directory
    if not root_dir.exists():
        print(json.dumps({"error": f"Directory not found: {root_dir}"}), file=sys.stderr)
        sys.exit(1)

    # Discover and validate configs
    modules, errors = discover_configs(root_dir)

    if errors:
        # Output errors as JSON array
        error_list = [
            {"error": e.message, "file": e.file} if e.file else {"error": e.message}
            for e in errors
        ]
        print(json.dumps(error_list), file=sys.stderr)
        sys.exit(1)

    # Generate plan
    plan_modules, conflicts = generate_plan(
        modules,
        os_filter=args.os,
        os_version=args.os_version,
        module_filter=args.modules,
    )

    # Check for conflicts
    if conflicts:
        conflict_json = {
            "error": "conflict",
            "conflicts": [
                {"destination": c.destination, "sources": c.sources}
                for c in conflicts
            ]
        }
        print(json.dumps(conflict_json), file=sys.stderr)
        sys.exit(1)

    # Output successful plan
    plan = {"modules": [
        {"name": m.name, "actions": m.actions}
        for m in plan_modules
    ]}
    print(json.dumps(plan, indent=2))


if __name__ == "__main__":
    main()

